import abc

# Product
class Car:
    def __init__(self):
        self.model = None
        self.engine = None
        self.color = None
        self.wheels = None

    def __str__(self):
        return f"Car: {self.color} {self.model} with {self.engine} engine and {self.wheels} wheels."


# Abstract Builder
class CarBuilder(abc.ABC):
    def __init__(self):
        self._car = Car()

    @abc.abstractmethod
    def set_model(self, model: str):
        pass

    @abc.abstractmethod
    def set_engine(self, engine: str):
        pass

    @abc.abstractmethod
    def set_color(self, color: str):
        pass

    @abc.abstractmethod
    def set_wheels(self, wheels: str):
        pass

    def get_result(self) -> Car:
        return self._car


# Concrete Builders
class SportsCarBuilder(CarBuilder):
    def __init__(self):
        super().__init__()
        self._car = Car() # Reset product for a new build

    def set_model(self, model: str):
        self._car.model = model
        return self # Enable method chaining

    def set_engine(self, engine: str):
        self._car.engine = engine
        return self

    def set_color(self, color: str):
        self._car.color = color
        return self

    def set_wheels(self, wheels: str):
        self._car.wheels = wheels
        return self


class CityCarBuilder(CarBuilder):
    def __init__(self):
        super().__init__()
        self._car = Car() # Reset product for a new build

    def set_model(self, model: str):
        self._car.model = model
        return self

    def set_engine(self, engine: str):
        self._car.engine = engine
        return self

    def set_color(self, color: str):
        self._car.color = color
        return self

    def set_wheels(self, wheels: str):
        self._car.wheels = wheels
        return self


# Director
class CarManufacture:
    def __init__(self):
        self._builder = None

    @property
    def builder(self) -> CarBuilder:
        return self._builder

    @builder.setter
    def builder(self, builder: CarBuilder):
        self._builder = builder

    def construct_sports_car(self):
        if not self._builder:
            raise ValueError("Builder not set.")
        self._builder.set_model("SuperSport X") \
                     .set_engine("V8 Turbo") \
                     .set_color("Red") \
                     .set_wheels("Sport Alloys")

    def construct_city_car(self):
        if not self._builder:
            raise ValueError("Builder not set.")
        self._builder.set_model("Urban Commuter Z") \
                     .set_engine("1.2L Economical") \
                     .set_color("Blue") \
                     .set_wheels("Standard Steel")


# Client code
if __name__ == "__main__":
    director = CarManufacture()

    print("Building a Sports Car:")
    sports_car_builder = SportsCarBuilder()
    director.builder = sports_car_builder
    director.construct_sports_car()
    sports_car = sports_car_builder.get_result() # Client retrieves product from builder
    print(sports_car)
    print("-" * 30)

    print("Building a City Car:")
    city_car_builder = CityCarBuilder()
    director.builder = city_car_builder
    director.construct_city_car()
    city_car = city_car_builder.get_result()
    print(city_car)
    print("-" * 30)

    print("Building a Custom Car directly (without Director):")
    custom_car = SportsCarBuilder() \
        .set_model("Custom Rocket") \
        .set_engine("Electric Hyper") \
        .set_color("Green Metallic") \
        .set_wheels("Carbon Fiber") \
        .get_result()
    print(custom_car)
    print("-" * 30)
